{"code": "import json
import re
from datetime import datetime
import pandas as pd

# Load the query result from the stored file
result_file = var_functions.query_db:2
with open(result_file, 'r') as f:
    patents_data = json.load(f)

# Filter for Germany (DE) patents granted in second half of 2019
german_patents = []
for patent in patents_data:
    patents_info = patent['Patents_info']
    grant_date = patent['grant_date']
    cpc_data = patent['cpc']

    # Check if it's a Germany patent
    if 'DE-' in patents_info or 'from DE' in patents_info:
        # Parse grant date
        try:
            # Extract month from grant_date
            date_patterns = [
                r'(\d{1,2})(?:st|nd|rd|th)?\s+([A-Za-z]+)(?:,\s+|\s+)?(2019)',
                r'([A-Za-z]+)\s+(\d{1,2})(?:st|nd|rd|th)?(?:,\s+|\s+)?(2019)',
                r'(\d{1,2})/\d{1,2}/2019'
            ]

            month = None
            for pattern in date_patterns:
                match = re.search(pattern, grant_date)
                if match:
                    if pattern == date_patterns[0]:
                        month_str = match.group(2)
                        month_num = datetime.strptime(month_str, '%B').month
                        month = month_num
                    elif pattern == date_patterns[1]:
                        month_str = match.group(1)
                        month_num = datetime.strptime(month_str, '%B').month
                        month = month_num
                    elif pattern == date_patterns[2]:
                        month = int(match.group(1))
                    break

            # Check if in second half (July-December)
            if month and month >= 7:
                # Parse CPC codes
                if cpc_data and cpc_data.strip():
                    try:
                        cpc_list = json.loads(cpc_data)
                        for cpc_entry in cpc_list:
                            code = cpc_entry.get('code', '')
                            if code and len(code.split('/')[0]) >= 4:
                                german_patents.append({
                                    'patent_info': patents_info,
                                    'cpc_code': code,
                                    'grant_date': grant_date,
                                    'month': month,
                                    'year': 2019
                                })
                    except:
                        continue
        except:
            continue

# Create DataFrame
df = pd.DataFrame(german_patents)
print(f"Total German patents in second half 2019: {len(df)}")

if not df.empty:
    print(f"Sample data:\n{df.head()}")
    print(f"CPC codes extracted: {df['cpc_code'].nunique()} unique codes")
else:
    print("No German patents found for second half of 2019")

# Save intermediate results
result_summary = {
    'total_patents': len(df),
    'sample_patents': german_patents[:5] if german_patents else [],
    'unique_cpc_codes': df['cpc_code'].nunique() if not df.empty else 0
}

print('__RESULT__:')
print(json.dumps(result_summary, indent=2))"}

{"code": "import json

# Load German patents data
german_file = var_functions.execute_python:10
with open(german_file, 'r') as f:
    german_data = json.load(f)

# Get top CPC groups
top_groups = [group for group, count in german_data['top_groups']]
print("Top CPC groups:", top_groups)

# Load CPC definitions
cpc_file = var_functions.query_db:18
with open(cpc_file, 'r') as f:
    cpc_definitions = json.load(f)

print(f"Total CPC definitions loaded: {len(cpc_definitions)}")

# Find level information and symbols
level_stats = {}
symbol_patterns = {}

for def_item in cpc_definitions:
    symbol = def_item.get('symbol', '')
    level = def_item.get('level', '')
    title = def_item.get('titleFull', '')

    # Track level statistics
    try:
        level_num = int(float(level))
        level_stats[level_num] = level_stats.get(level_num, 0) + 1
    except:
        pass

    # Check if symbol starts with any of our top groups
    for group in top_groups:
        if symbol.startswith(group):
            if group not in symbol_patterns:
                symbol_patterns[group] = []
            symbol_patterns[group].append({
                'symbol': symbol,
                'level': level,
                'title': title
            })

print("Level statistics:", level_stats)
print("\nSymbol patterns for top groups:")
for group, symbols in symbol_patterns.items():
    print(f"\n{group}: {len(symbols)} symbols")
    for sym in symbols[:3]:
        print(f"  Level {sym['level']}: {sym['symbol']} - {sym['title'][:80]}...")

# Find exact level 4 matches for top groups
level_4_matches = []
for def_item in cpc_definitions:
    symbol = def_item.get('symbol', '')
    level = def_item.get('level', '')
    title = def_item.get('titleFull', '')

    try:
        level_num = int(float(level))
        if level_num == 4 and symbol in top_groups:
            level_4_matches.append({
                'symbol': symbol,
                'titleFull': title
            })
    except:
        continue

print(f"\nFound {len(level_4_matches)} exact level 4 matches:")
for match in level_4_matches:
    print(f"  {match['symbol']}: {match['titleFull'][:80]}...")

result = {
    'top_groups': top_groups,
    'level_stats': level_stats,
    'level_4_matches': level_4_matches
}

print('__RESULT__:')
print(json.dumps(result, indent=2))"}

{"code": "import json

# Access stored data
german_file = locals()['var_functions.execute_python:10']
cpc_file = locals()['var_functions.query_db:18']

with open(german_file, 'r') as f:
    german_data = json.load(f)

with open(cpc_file, 'r') as f:
    cpc_defs = json.load(f)

# Count patents per CPC group level 4
group_counts = {}
for patent in german_data['all_data']:
    group = patent['cpc_group_4']
    group_counts[group] = group_counts.get(group, 0) + 1

# Find level 4 titles
titles = {}
for item in cpc_defs:
    symbol = item.get('symbol', '')
    level = item.get('level', '')
    title = item.get('titleFull', '')

    try:
        if int(float(level)) == 4 and symbol in group_counts:
            titles[symbol] = title
    except:
        pass

# Calculate EMA for top groups
alpha = 0.1
results = []

for group_code in list(group_counts.keys())[:15]:
    # Get monthly counts
    monthly = {}
    for patent in german_data['all_data']:
        if patent['cpc_group_4'] == group_code:
            month = patent['month']
            monthly[month] = monthly.get(month, 0) + 1

    # Calculate EMA
    ema = 0
    best_month = 0
    best_ema = 0

    for month in range(7, 13):
        current = monthly.get(month, 0)
        ema = alpha * current + (1 - alpha) * ema
        if ema > best_ema:
            best_ema = ema
            best_month = month

    results.append({
        'cpc_group_code': group_code,
        'title_full': titles.get(group_code, 'Not found'),
        'total_patents': group_counts[group_code],
        'best_month': best_month,
        'ema_value': round(best_ema, 2)
    })

# Sort by EMA
results.sort(key=lambda x: x['ema_value'], reverse=True)

# Create final output
output = {
    'summary': {
        'total_patents': len(german_data['all_data']),
        'total_groups': len(group_counts),
        'analysis_period': 'H2 2019'
    },
    'top_groups': results[:10]
}

print('__RESULT__:')
print(json.dumps(output))"}

